customEChartConfig:
{{ ((chartType) => ( 
(() => {
  const raw = Renewal_List.filteredTableData || Renewal_List.tableData || [];
  const start = new Date(ContractDateFrom.selectedDate);
  const end = new Date(ContractDateTo.selectedDate);

  // 1. Für jede opp_id: Vertrag mit spätestem contract_expired_date im Zeitraum
  const latestContractByOpp = {};
  raw.forEach(r => {
    if (!r.opportunity_id || !r.contract_expired_date) return;
    const date = new Date(r.contract_expired_date);
    if (date < start || date > end) return;

    if (
      !latestContractByOpp[r.opportunity_id] ||
      date > new Date(latestContractByOpp[r.opportunity_id].contract_expired_date)
    ) {
      latestContractByOpp[r.opportunity_id] = r;
    }
  });

  // 2. Nutze den Status direkt aus der Tabelle
  const deduped = Object.values(latestContractByOpp).map(r => {
    const rawStatus = (r.Status ?? '').toString().trim();

    // Gleiche Logik wie linke Chart: Bei leerem Status days_until prüfen
    let status;
    if (!rawStatus) {
      const daysUntil = r.days_until_expiration;
      status = daysUntil <= 180 ? 'To Assess' : 'Upcoming';
    } else {
      status = rawStatus;
    }

    return {
      status: status,
      booking_amount: parseFloat(r.booking_amount || 0),
      renewed_booking_amount: parseFloat(r.renewed_booking_amount || 0)
    };
  }).filter(r => r.status !== 'Data Issue');  // ← DATA ISSUE RAUSFILTERN

  // 3. Aggregiere nach Status
  const aggregated = deduped.reduce((acc, r) => {
    const key = r.status;
    if (!acc[key]) {
      acc[key] = { count: 0, amount: 0 };
    }
    acc[key].count += 1;
    acc[key].amount += key === 'Closed Won' ? r.renewed_booking_amount : r.booking_amount;
    return acc;
  }, {});

  const entriesSorted = Object.entries(aggregated)
    .sort(([, a], [, b]) => b.count - a.count);

  const labels = entriesSorted.map(([name]) => name);
  const maxCount = Math.max(...entriesSorted.map(([, data]) => data.count));

  const colors = {
    'Upcoming': '#757575',       // Dunkleres Grau
    'To Assess': '#BDBDBD',      // Hellgrau
    'Low Risk': '#9ccc65',       // Hellgrün
    'At Risk': '#e53935',        // Rot
    'Closed Won': '#13734b',     // Dunkelgrün
    'Renewal Lost': '#800020'    // Dunkelrot
  };

  const formatAmount = (amount) => {
    if (amount >= 1000000) {
      return `€${(amount / 1000000).toFixed(1)}M`;
    } else if (amount >= 1000) {
      return `€${(amount / 1000).toFixed(0)}k`;
    } else {
      return `€${amount.toFixed(0)}`;
    }
  };

  const getTextColor = (status) => {
    // Weiße Schrift für dunkle Farben
    if (status === 'Closed Won' || status === 'Renewal Lost' || status === 'At Risk' || status === 'Upcoming') {
      return '#fff';
    }
    // Schwarze Schrift für helle Farben
    return '#000';
  };

  return {
    tooltip: {
      trigger: 'item'
    },
    grid: {
      left: '30%',
      right: '25%',
      top: '5%',
      bottom: '5%',
      containLabel: false
    },
    xAxis: { type: 'value', show: false, max: maxCount },
    yAxis: {
      type: 'category',
      show: true,
      axisLine: { show: false },
      axisTick: { show: false },
      axisLabel: { show: true, color: '#333', fontSize: 12 },
      data: labels
    },
    series: [{
      type: 'bar',
      label: {
        show: true,
        position: 'inside',
        fontWeight: 'bold',
        fontSize: 11
      },
      data: entriesSorted.map(([name, data]) => {
        return {
          value: data.count,
          name,
          label: {
            color: getTextColor(name),
            formatter: data.count.toString()
          },
          itemStyle: {
            color: colors[name] || '#CCCCCC'
          }
        };
      })
    }, {
      type: 'bar',
      barGap: '-100%',
      label: {
        show: true,
        position: 'right',
        color: '#000',
        fontWeight: 'bold',
        fontSize: 11,
        align: 'left',
        offset: [5, 0]
      },
      data: entriesSorted.map(([name, data]) => {
        const formattedAmount = formatAmount(data.amount);
        return {
          value: maxCount,
          name,
          label: {
            formatter: `(${formattedAmount})`
          },
          itemStyle: {
            color: 'transparent'
          }
        };
      })
    }]
  };
})()
))(RiskChart.chartType) }}
